import { Injectable } from '@angular/core';
import { Observable, of, throwError } from 'rxjs';
import { HttpClient, HttpHeaders, HttpErrorResponse } from '@angular/common/http';
import { catchError, tap, map } from 'rxjs/operators';

const httpOptions = {
  headers: new HttpHeaders({ 'Content-Type': 'application/json' })
};
const apiUrl = 'https://api.covid19api.com';

@Injectable({
  providedIn: 'root'
})
export class ApiService {

  constructor(private http: HttpClient) { }

  private handleError<T>(operation = 'operation', result?: T) {
    return (error: any): Observable<T> => {
      console.error(error); // log to console instead
      return of(result as T);
    };
  }

  getSummary(): Observable<any[]> {
    return this.http.get<any[]>(`${apiUrl}/summary`)
      .pipe(
        tap(cases => console.log('A summary of new and total cases per country updated daily.')),
        catchError(this.handleError('getSummary', []))
      );
  }

  getDetails(country: string): Observable<any[]> {
    return this.http.get<any[]>(`${apiUrl}/country/${country}/status/confirmed/live`)
      .pipe(
        tap(cases => console.log('By Country Live.')),
        catchError(this.handleError('getDetails', []))
      );
  }
}
